function PropertyDetail({ property }) {
  const { div, h1, h2, p, span, img } = tags;
  const [activeTab, setActiveTab] = createSignal('overview');

  const noi = property.monthlyRevenue - property.monthlyExpenses;
  const noiMargin = Math.round((noi / property.monthlyRevenue) * 100);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _aic _gap2 _mb2') },
      link({ href: '/properties', class: css('_fgmuted _hoverFg') }, icon('arrow-left'), ' Properties')
    ),
    div({ class: css('_flex _jcsb _aic') },
      div({},
        div({ class: css('_flex _aic _gap3') },
          h1({ class: css('_heading2') }, property.name || property.address),
          Badge({ variant: property.status === 'active' ? 'success' : 'default' }, property.status)
        ),
        p({ class: css('_fgmuted') }, `${property.address}, ${property.city}, ${property.state} ${property.zip}`)
      ),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline' }, icon('edit'), 'Edit'),
        Button({ variant: 'outline' }, icon('more-vertical'))
      )
    ),
    div({ class: css('_grid _cols4 _gap1 _r2 _overflow[hidden]') },
      img({ src: property.images?.[0], class: css('_col[span-2] _row[span-2] _wfull _hfull _objcover') }),
      ...property.images?.slice(1, 5).map(src => img({ src, class: css('_wfull _h32 _objcover') }))
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgsuccess') }, `${property.occupancyRate}%`),
        span({ class: css('_textsm _fgmuted') }, 'Occupancy')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${property.monthlyRevenue.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Monthly Revenue')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${property.monthlyExpenses.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Monthly Expenses')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${noi.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, `NOI (${noiMargin}% margin)`)
      )
    ),
    Tabs({ value: activeTab(), onValueChange: setActiveTab },
      Tabs.List({},
        Tabs.Trigger({ value: 'overview' }, 'Overview'),
        Tabs.Trigger({ value: 'units' }, `Units (${property.units})`),
        Tabs.Trigger({ value: 'financials' }, 'Financials'),
        Tabs.Trigger({ value: 'documents' }, 'Documents'),
        Tabs.Trigger({ value: 'maintenance' }, 'Maintenance')
      ),
      Tabs.Content({ value: 'overview' }, PropertyOverview({ property })),
      Tabs.Content({ value: 'units' }, UnitList({ propertyId: property.id })),
      Tabs.Content({ value: 'financials' }, PropertyFinancials({ property })),
      Tabs.Content({ value: 'documents' }, PropertyDocuments({ property })),
      Tabs.Content({ value: 'maintenance' }, PropertyMaintenance({ property }))
    )
  );
}

