function PropertyForm({ property, onSave, onCancel }) {
  const { div, form, h1, label } = tags;
  const [formData, setFormData] = createSignal(property || { name: '', address: '', city: '', state: '', zip: '', type: 'residential', yearBuilt: '', sqft: '' });

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(formData());
  };

  return div({ class: css('_maxw[800px]') },
    h1({ class: css('_heading3 _mb6') }, property ? 'Edit Property' : 'Add Property'),
    form({ class: css('_flex _col _gap6'), onsubmit: handleSubmit },
      div({ class: css('_grid _cols2 _gap4') },
        div({ class: css('_col[span-2]') },
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Property Name'),
          Input({ value: formData().name, oninput: e => setFormData({ ...formData(), name: e.target.value }), placeholder: 'Optional display name' })
        ),
        div({ class: css('_col[span-2]') },
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Street Address'),
          Input({ value: formData().address, oninput: e => setFormData({ ...formData(), address: e.target.value }), required: true })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'City'),
          Input({ value: formData().city, oninput: e => setFormData({ ...formData(), city: e.target.value }), required: true })
        ),
        div({ class: css('_grid _cols2 _gap4') },
          div({},
            label({ class: css('_textsm _font500 _mb1 _block') }, 'State'),
            Select({ value: formData().state, onchange: e => setFormData({ ...formData(), state: e.target.value }) },
              tags.option({ value: '' }, 'Select...'),
              tags.option({ value: 'CA' }, 'California'),
              tags.option({ value: 'TX' }, 'Texas')
              // ... other states
            )
          ),
          div({},
            label({ class: css('_textsm _font500 _mb1 _block') }, 'ZIP'),
            Input({ value: formData().zip, oninput: e => setFormData({ ...formData(), zip: e.target.value }), required: true })
          )
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Property Type'),
          Select({ value: formData().type, onchange: e => setFormData({ ...formData(), type: e.target.value }) },
            tags.option({ value: 'residential' }, 'Residential'),
            tags.option({ value: 'multi-family' }, 'Multi-Family'),
            tags.option({ value: 'commercial' }, 'Commercial')
          )
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Year Built'),
          Input({ type: 'number', value: formData().yearBuilt, oninput: e => setFormData({ ...formData(), yearBuilt: e.target.value }) })
        ),
        div({},
          label({ class: css('_textsm _font500 _mb1 _block') }, 'Square Feet'),
          Input({ type: 'number', value: formData().sqft, oninput: e => setFormData({ ...formData(), sqft: e.target.value }) })
        )
      ),
      div({ class: css('_flex _jce _gap2 _pt4 _borderT') },
        Button({ type: 'button', variant: 'outline', onclick: onCancel }, 'Cancel'),
        Button({ type: 'submit', variant: 'primary' }, property ? 'Save Changes' : 'Create Property')
      )
    )
  );
}

